templates.css_template:
.lt-container {
    padding: 0;
    font-family: '{{FONT_FAMILY}}', sans-serif;
    line-height: {{LINE_HEIGHT}};
}
.plate {
    background: {{PRIMARY_BG}};
    padding: 20px 40px;
    border-left: 10px solid {{SECONDARY_COLOR}};
    color: white;
    display: inline-block;
    box-shadow: {{BOX_SHADOW}};
    opacity: 0;
    transform: {{ANIMATION_IN_TRANSFORM}};
    transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
}
.title {
    margin: 0;
    font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: {{TITLE_TRANSFORM}};
    letter-spacing: -1px;
}

.modern-lt-container {
    padding: 0;
    font-family: '{{FONT_FAMILY}}', sans-serif;
    line-height: {{LINE_HEIGHT}};
}
.modern-plate {
    background: {{PRIMARY_BG}};
    padding: 24px 48px;
    border-radius: 12px;
    color: white;
    display: inline-block;
    box-shadow: {{BOX_SHADOW}};
    opacity: 0;
    transform: {{ANIMATION_IN_TRANSFORM}};
    transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
    border: 1px solid rgba(255,255,255,0.1);
    backdrop-filter: blur(10px);
}
.modern-title {
    margin: 0;
    font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: {{TITLE_TRANSFORM}};
    letter-spacing: 1px;
    text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
}
.modern-plate {
    position: relative;
    overflow: hidden;
}
.modern-plate::after {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 50%;
    height: 100%;
    background: linear-gradient(to right, rgba(255,255,255,0) 0%, rgba(255,255,255,0.3) 50%, rgba(255,255,255,0) 100%);
    transform: skewX(-20deg);
    animation: shine 6s infinite;
}
@keyframes shine {
    0% { left: -100%; }
    20% { left: 200%; }
    100% { left: 200%; }
}

templates.js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector('.modern-ticker');
    const tickerTrack = root.querySelector('.ticker-track');
    root.__slt_show = () => {
        const tl = GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}});
        if (tickerTrack) {
            tl.add(() => {
                const trackWidth = tickerTrack.scrollWidth || 0;
                const speedPxPerSec = (parseFloat("{{speed}}") || parseFloat("{{TICKER_SPEED}}") || 50);
                if (speedPxPerSec > 0 && trackWidth > 0) {
                    const duration = trackWidth / speedPxPerSec;
                    gsap.to(tickerTrack, {
                        x: -trackWidth,
                        duration: duration,
                        ease: 'none',
                        repeat: -1
                    });
                }
            });
        }
        return tl;
    };
    root.__slt_hide = () => {
        gsap.killTweensOf(tickerTrack);
        const tl = GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}});
        return tl;
    };
})();

templates.css_template:
