    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}
#{{ID}} .rep-top-bar {
    flex: 1;
    background: {{PRIMARY_BG}};
    color: {{TITLE_COLOR}};
    display: flex;
    align-items: center;
    padding: 0 30px;
    position: relative;
    overflow: hidden;
}
#{{ID}} .rep-title {
    font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: {{TITLE_TRANSFORM}};
    white-space: pre-line;
    z-index: 2;
    letter-spacing: -0.5px;
}
#{{ID}} .rep-side-graphic {
    position: absolute;
    right: 0;
    top: 0;
    bottom: 0;
    width: 300px;
    background: url('{{SIDE_IMAGE}}') center/cover;
    opacity: 0.8;
}
#{{ID}} .rep-side-graphic::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(to right, {{SECONDARY_COLOR}} 0%, transparent 100%);
}
#{{ID}} .rep-bottom-bar {
    height: 40px;
    background: {{PRIMARY_BG}};
    display: flex;
    align-items: center;
    position: relative;
    overflow: hidden;
}
#{{ID}} .ticker-track {
    display: flex;
    align-items: center;
    white-space: nowrap;
    animation: rep-scroll 25s linear infinite;
    padding-left: 100%;
}
#{{ID}} .ticker-item {
    color: {{TITLE_COLOR}};
    font-size: 24px;
    font-weight: 600;
    text-transform: uppercase;
    padding: 0 20px;
    margin-top: {{PADDING_Y}}px;
}
#{{ID}} .ticker-sep {
    width: 12px;
    height: 24px;
    background: {{BORDER_COLOR}};
    transform: skewX(-30deg);
    margin: 0 10px;
}
@keyframes rep-scroll { 0% { transform: translateX(0); } 100% { transform: translateX(-100%); } }

templates.js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector(".rep-container");
    const clockEl = root.querySelector(".rep-clock");
    const tickerTrack = root.querySelector(".ticker-track");
    let timer;
    const updateTime = () => {
        const now = new Date();
        const h = String(now.getHours());
        const m = String(now.getMinutes()).padStart(2, "0");
        if(clockEl) clockEl.textContent = h + ":" + m;
    };
    root.__slt_show = () => {
        const tl = GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}});
        const textTl = GSAPFX.applyTextEffect(root, {{{TEXT_ANIM_JSON}}});
        if (textTl) tl.add(textTl, {{{TEXT_ANIM_SYNC}}} ? ">-0.1" : 0);
        updateTime();
        timer = setInterval(updateTime, 1000);
        return tl;
    };
    root.__slt_hide = () => {
        if (typeof timer !== "undefined") clearInterval(timer);
        const tl = GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}});
        const textTl = GSAPFX.applyTextOutEffect(root, {{{TEXT_ANIM_OUT_JSON}}});
        if (textTl) tl.add(textTl, 0);
        return tl;
    };
})();

