templates.js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector('.news-container-v8');
    const textElement = root.querySelector('.news-text-v8');
    const wiper = root.querySelector('.wiper-v8');
    const dataEl = root.querySelector('#f-news-list');
    if(!textElement || !container || !dataEl) return;

    let newsList = [];
    try { 
        newsList = JSON.parse(dataEl.innerHTML || "[]"); 
    } catch(e) { 
        newsList = ["BRAK DANYCH"]; 
    }
    if(newsList.length === 0) newsList = ["BRAK WIADOMOŚCI"];

    let currentIndex = 0;
    let activeTimeouts = [];
    let cycleRunning = false;

    function adjustFontSize() {
        const baseFontSizeStr = "{{TITLE_SIZE}}";
        const baseFontSize = parseFloat(baseFontSizeStr) || 40;
        const wiperEl = root.querySelector('.wiper-v8');
        const wiperWidth = wiperEl ? wiperEl.offsetWidth : 0;
        if (wiperEl) {
            container.style.setProperty('--wiper-width', wiperWidth + 'px');
        }
        const leftPadding = wiperEl ? (wiperWidth + 20) : 20;
        const maxWidth = container.offsetWidth - (leftPadding + 20);

        textElement.style.paddingLeft = leftPadding + 'px';
        textElement.style.fontSize = baseFontSize + "px";

        let currentWidth = textElement.scrollWidth - leftPadding;
        if (currentWidth > maxWidth && currentWidth > 0) {
            const newSize = (maxWidth / currentWidth) * baseFontSize;
            textElement.style.fontSize = Math.min(newSize, baseFontSize) + "px";
        }
    }

    function runCycle() {
        if (!cycleRunning) return;
        textElement.classList.remove('visible');
        textElement.innerText = newsList[currentIndex];
        adjustFontSize();

        activeTimeouts.push(setTimeout(() => {
            if(!cycleRunning) return;
            textElement.classList.add('visible');
        }, 100));

        activeTimeouts.push(setTimeout(() => {
            if(!cycleRunning) return;
            textElement.classList.remove('visible');
            activeTimeouts.push(setTimeout(() => {
                if(!cycleRunning) return;
                if(wiper) wiper.className = 'wiper-v8 move-right';
                activeTimeouts.push(setTimeout(() => {
                    if(!cycleRunning) return;
                    if(wiper) wiper.className = 'wiper-v8 snap-back';
                    activeTimeouts.push(setTimeout(() => {
                        if(!cycleRunning) return;
                        currentIndex = (currentIndex + 1) % newsList.length;
                        runCycle();
                    }, 500));
                }, 1000));
            }, 400));
        }, 4000));
    }

    root.__slt_show = () => {
        cycleRunning = true;
        const tl = gsap.timeline();
        tl.to(container, { opacity: 1, y: 0, duration: 0.6, ease: "power2.out" });
        tl.add(() => {
            runCycle();
        }, "+ =0.1");
        return tl;
    };

    root.__slt_hide = () => {
        cycleRunning = false;
        activeTimeouts.forEach(t => clearTimeout(t));
        activeTimeouts = [];
        const tl = gsap.timeline();
        tl.to(container, { opacity: 0, y: 100, duration: 0.4, ease: "power2.in" });
        return tl;
    };

    window.addEventListener('resize', adjustFontSize);
})();

